import React, { useEffect, useRef, useState, useCallback } from 'react';
import Quagga from 'quagga';
import './BarcodeScanner.css';

const BarcodeScanner = ({ onScan, onError }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [scanStatus, setScanStatus] = useState('idle'); // idle, scanning, success, error
  const scannerRef = useRef(null);
  const lastDetectionRef = useRef({ code: null, timestamp: 0 });
  const statusTimeoutRef = useRef(null);

  const SCAN_COOLDOWN = 2000; // 2 seconds between same barcode
  const STATUS_DISPLAY_TIME = 2000; // Show success/error for 2s

  const resetStatus = useCallback(() => {
    if (statusTimeoutRef.current) {
      clearTimeout(statusTimeoutRef.current);
    }
    statusTimeoutRef.current = setTimeout(() => {
      setScanStatus('idle');
    }, STATUS_DISPLAY_TIME);
  }, []);

  const handleDetected = useCallback((result) => {
    if (!result || !result.codeResult) return;

    const code = String(result.codeResult.code).trim().toUpperCase();
    const now = Date.now();
    const last = lastDetectionRef.current;

    // Cooldown check - prevent rapid duplicate scans
    if (code === last.code && (now - last.timestamp) < SCAN_COOLDOWN) {
      return;
    }

    lastDetectionRef.current = { code, timestamp: now };
    setScanStatus('scanning');

    // Call parent handler with immediate UI feedback
    onScan?.(code, {
      onSuccess: () => {
        setScanStatus('success');
        resetStatus();
      },
      onError: (error) => {
        setScanStatus('error');
        resetStatus();
        onError?.(error);
      }
    });
  }, [onScan, onError, resetStatus]);

  useEffect(() => {
    if (!isScanning || !scannerRef.current) return;

    const config = {
      inputStream: {
        name: 'Live',
        type: 'LiveStream',
        target: scannerRef.current,
        constraints: {
          facingMode: 'environment',
          aspectRatio: { min: 1, max: 2 }
        },
        area: { top: '25%', right: '15%', left: '15%', bottom: '25%' }
      },
      decoder: {
        readers: ['code_128_reader', 'ean_reader', 'upc_reader', 'code_39_reader'],
        multiple: false
      },
      locate: true,
      numOfWorkers: 2,
      frequency: 5
    };

    Quagga.init(config, (err) => {
      if (err) {
        console.error('Scanner init error:', err);
        onError?.('Camera initialization failed');
        setIsScanning(false);
        return;
      }
      Quagga.start();
    });

    Quagga.onDetected(handleDetected);

    return () => {
      Quagga.stop();
      Quagga.offDetected(handleDetected);
      if (statusTimeoutRef.current) {
        clearTimeout(statusTimeoutRef.current);
      }
    };
  }, [isScanning, handleDetected, onError]);

  return (
    <div className="barcode-scanner">
      <div className="scanner-header">
        <h3>Barcode Scanner</h3>
        <div className={`scan-status scan-status-${scanStatus}`}>
          {scanStatus === 'success' && '✓ Scanned'}
          {scanStatus === 'error' && '✗ Failed'}
          {scanStatus === 'scanning' && '⟳ Processing...'}
        </div>
      </div>

      <div className={`scanner-viewport ${scanStatus}`} ref={scannerRef}>
        {!isScanning && (
          <div className="scanner-overlay">
            <p>Ready to scan</p>
          </div>
        )}
        {isScanning && <div className="scan-frame" />}
      </div>

      <button 
        onClick={() => setIsScanning(!isScanning)} 
        className={`btn ${isScanning ? 'btn-secondary' : 'btn-primary'}`}
      >
        {isScanning ? '⏸ Stop Scanner' : '📷 Start Scanner'}
      </button>
    </div>
  );
};

export default BarcodeScanner;
